import{_ as e,c as t,o as r,a1 as o}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Invalid Grant 문제 해결: 계정 비활성화 복구 | Antigravity-Manager","description":"invalid_grant 오류의 의미와 자동 처리 논리를 학습합니다. refresh_token 무효화 후 OAuth를 통해 계정을 다시 추가하여 자동 비활성화 해제를 트리거하고 복구가 Proxy에 적용되는지 확인하세요.","frontmatter":{"title":"Invalid Grant 문제 해결: 계정 비활성화 복구 | Antigravity-Manager","sidebarTitle":"계정이 비활성화되었을 때 복구 방법","subtitle":"invalid_grant 및 계정 자동 비활성화: 발생 이유, 복구 방법","description":"invalid_grant 오류의 의미와 자동 처리 논리를 학습합니다. refresh_token 무효화 후 OAuth를 통해 계정을 다시 추가하여 자동 비활성화 해제를 트리거하고 복구가 Proxy에 적용되는지 확인하세요.","tags":["FAQ","오류 문제 해결","OAuth","계정 관리","invalid_grant"],"prerequisite":["start-add-account","start-first-run-data","advanced-scheduling"],"order":1},"headers":[],"relativePath":"ko/lbjlaq/Antigravity-Manager/faq/invalid-grant/index.md","filePath":"ko/lbjlaq/Antigravity-Manager/faq/invalid-grant/index.md"}'),i={name:"ko/lbjlaq/Antigravity-Manager/faq/invalid-grant/index.md"};function d(n,a,s,l,c,h){return r(),t("div",null,[...a[0]||(a[0]=[o(`<h1 id="invalid-grant-및-계정-자동-비활성화-발생-이유-복구-방법" tabindex="-1">invalid_grant 및 계정 자동 비활성화: 발생 이유, 복구 방법 <a class="header-anchor" href="#invalid-grant-및-계정-자동-비활성화-발생-이유-복구-방법" aria-label="Permalink to &quot;invalid_grant 및 계정 자동 비활성화: 발생 이유, 복구 방법&quot;">​</a></h1><h2 id="이-과정을-통해-할-수-있는-것" tabindex="-1">이 과정을 통해 할 수 있는 것 <a class="header-anchor" href="#이-과정을-통해-할-수-있는-것" aria-label="Permalink to &quot;이 과정을 통해 할 수 있는 것&quot;">​</a></h2><ul><li><code>invalid_grant</code>를 보았을 때 어떤 refresh_token 문제 유형인지 알 수 있음</li><li>&quot;계정이 갑자기 사용할 수 없게 되는 이유&quot; 명확히 이해: 어떤 상황에서 자동으로 비활성화되는지, 비활성화 후 시스템이 어떻게 처리하는지</li><li>가장 짧은 경로로 계정을 복구하고 복구가 실행 중인 Proxy에 이미 적용되는지 확인</li></ul><h2 id="겪고-있는-증상" tabindex="-1">겪고 있는 증상 <a class="header-anchor" href="#겪고-있는-증상" aria-label="Permalink to &quot;겪고 있는 증상&quot;">​</a></h2><ul><li>로컬 Proxy를 호출할 때 갑자기 실패하고 오류 메시지에 <code>invalid_grant</code>가 나타남</li><li>명백히 계정이 Accounts 목록에 있는데 Proxy가 계속해서 건너뜀(또는 &quot;다시 사용되지 않는 것&quot;처럼 느껴짐)</li><li>소량의 계정만 있는 경우, 한 번 <code>invalid_grant</code>를 만난 후 전체 가용성이 명백하게 나빠짐</li></ul><h2 id="invalid-grant란" tabindex="-1">invalid_grant란? <a class="header-anchor" href="#invalid-grant란" aria-label="Permalink to &quot;invalid_grant란?&quot;">​</a></h2><p><strong>invalid_grant</strong>는 Google OAuth가 <code>access_token</code>을 새로고침할 때 반환하는 오류 유형입니다. Antigravity Tools의 관점에서 이는 특정 계정의 <code>refresh_token</code>이 이미 취소되었거나 만료되었음을 의미하며, 계속 재시도하면 계속 실패하므로 시스템은 해당 계정을 사용할 수 없음으로 표시하고 프록시 풀에서 제거합니다.</p><h2 id="핵심-원리-시스템은-일시적으로-건너뜀-이-아니라-영구적으로-비활성화-함" tabindex="-1">핵심 원리: 시스템은 &quot;일시적으로 건너뜀&quot;이 아니라 &quot;영구적으로 비활성화&quot;함 <a class="header-anchor" href="#핵심-원리-시스템은-일시적으로-건너뜀-이-아니라-영구적으로-비활성화-함" aria-label="Permalink to &quot;핵심 원리: 시스템은 &quot;일시적으로 건너뜀&quot;이 아니라 &quot;영구적으로 비활성화&quot;함&quot;">​</a></h2><p>Proxy가 토큰 새로고침 오류 문자열에 <code>invalid_grant</code>가 포함되어 있는 것을 발견하면 두 가지 작업을 수행합니다:</p><ol><li><strong>계정을 disabled로 기록</strong>(계정 JSON에 저장)</li><li><strong>계정을 메모리 토큰 풀에서 제거</strong>(동일한 잘못된 계정이 반복적으로 선택되는 것을 방지)</li></ol><p>이것이 &quot;계정은 있는데 Proxy가 더 이상 사용하지 않음&quot;을 보게 되는 이유입니다.</p><div class="info custom-block"><p class="custom-block-title">disabled vs proxy_disabled</p><ul><li><code>disabled=true</code>: 계정이 &quot;완전히 비활성화&quot;됨(전형적인 원인은 <code>invalid_grant</code>). 계정 풀을 로드할 때 직접 건너뜁니다.</li><li><code>proxy_disabled=true</code>: 계정이 &quot;Proxy에 사용할 수 없음&quot;만 의미(수동 비활성화/일괄 작업/할당량 보호 관련 논리), 의미가 다름.</li></ul><p>이 두 가지 상태는 계정 풀 로드 시 개별적으로 판단됩니다: 먼저 <code>disabled</code>를 판단하고, 다음 할당량 보호 및 <code>proxy_disabled</code> 판단을 수행합니다.</p></div><h2 id="따라-해보세요" tabindex="-1">따라 해보세요 <a class="header-anchor" href="#따라-해보세요" aria-label="Permalink to &quot;따라 해보세요&quot;">​</a></h2><h3 id="_1단계-refresh-token-새로고칭으로-트리거된-invalid-grant인지-확인" tabindex="-1">1단계: refresh_token 새로고칭으로 트리거된 invalid_grant인지 확인 <a class="header-anchor" href="#_1단계-refresh-token-새로고칭으로-트리거된-invalid-grant인지-확인" aria-label="Permalink to &quot;1단계: refresh_token 새로고칭으로 트리거된 invalid_grant인지 확인&quot;">​</a></h3><p><strong>이유</strong>: <code>invalid_grant</code>는 여러 호출 체인에서 나타날 수 있지만, 이 프로젝트의 &quot;자동 비활성화&quot;는 <strong>access_token 새로고칭 실패</strong>시에만 트리거됩니다.</p><p>Proxy 로그에서 다음과 유사한 오류 로그를 볼 수 있습니다(키워드는 <code>Token 새로고칭 실패</code> + <code>invalid_grant</code>):</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Token 새로고칭 실패 (&lt;email&gt;): &lt;...invalid_grant...&gt;，다음 계정 시도</span></span>
<span class="line"><span>Disabling account due to invalid_grant (&lt;email&gt;): refresh_token likely revoked/expired</span></span></code></pre></div><p><strong>예상 결과</strong>: 동일한 계정이 <code>invalid_grant</code>를 나타낸 후 곧 다시 선택되지 않음(토큰 풀에서 제거되었기 때문).</p><h3 id="_2단계-계정-파일에서-disabled-필드-확인-선택-사항이지만-가장-정확함" tabindex="-1">2단계: 계정 파일에서 disabled 필드 확인(선택 사항이지만 가장 정확함) <a class="header-anchor" href="#_2단계-계정-파일에서-disabled-필드-확인-선택-사항이지만-가장-정확함" aria-label="Permalink to &quot;2단계: 계정 파일에서 disabled 필드 확인(선택 사항이지만 가장 정확함)&quot;">​</a></h3><p><strong>이유</strong>: 자동 비활성화는 &quot;저장&quot;된 것이므로 파일 내용을 확인하면 &quot;일시적인 로테이션&quot; 오해를 배제할 수 있습니다.</p><p>계정 파일은 애플리케이션 데이터 디렉토리의 <code>accounts/</code> 디렉토리에 위치합니다(데이터 디렉토리 위치 참조: <strong><a href="./../../start/first-run-data/">첫 시작 필수: 데이터 디렉토리, 로그, 트레이 및 자동 시작</a></strong>). 계정이 비활성화되면 파일에 이 세 가지 필드가 나타납니다:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;disabled&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;disabled_at&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1700000000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;disabled_reason&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;invalid_grant: ...&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>예상 결과</strong>: <code>disabled</code>가 <code>true</code>이고 <code>disabled_reason</code>에 <code>invalid_grant:</code> 접두사가 포함되어 있음.</p><h3 id="_3단계-계정-복구-권장-방법-동일-계정-다시-추가" tabindex="-1">3단계: 계정 복구(권장 방법: 동일 계정 다시 추가) <a class="header-anchor" href="#_3단계-계정-복구-권장-방법-동일-계정-다시-추가" aria-label="Permalink to &quot;3단계: 계정 복구(권장 방법: 동일 계정 다시 추가)&quot;">​</a></h3><p><strong>이유</strong>: 이 프로젝트의 &quot;복구&quot;는 Proxy에서 수동으로 스위치를 켜는 것이 아니라 &quot;명시적 토큰 업데이트&quot;를 통해 자동 비활성화 해제를 트리거하는 것입니다.</p><p><strong>Accounts</strong> 페이지로 이동하여 새 자격 증명으로 계정을 다시 추가하세요(두 가지 방법 중 하나 선택):</p><ol><li>OAuth 인증 프로세스 다시 진행(참조: <strong><a href="./../../start/add-account/">계정 추가: OAuth/Refresh Token 이중 채널 및 모범 사례</a></strong>)</li><li>새 <code>refresh_token</code>으로 다시 한 번 추가(시스템은 Google에서 반환한 이메일을 기준으로 upsert를 수행함)</li></ol><p>시스템이 이번 upsert의 <code>refresh_token</code> 또는 <code>access_token</code>이 이전 값과 다르고, 해당 계정이 이전에 <code>disabled=true</code> 상태였음을 감지하면 자동으로 다음을 지웁니다:</p><ul><li><code>disabled</code></li><li><code>disabled_reason</code></li><li><code>disabled_at</code></li></ul><p><strong>예상 결과</strong>: 계정이 더 이상 disabled 상태가 아니며 (Proxy가 실행 중인 경우) 계정 풀은 자동으로 reload되어 복구가 즉시 적용됩니다.</p><h3 id="_4단계-복구가-이미-proxy에-적용되는지-확인" tabindex="-1">4단계: 복구가 이미 Proxy에 적용되는지 확인 <a class="header-anchor" href="#_4단계-복구가-이미-proxy에-적용되는지-확인" aria-label="Permalink to &quot;4단계: 복구가 이미 Proxy에 적용되는지 확인&quot;">​</a></h3><p><strong>이유</strong>: 계정이 하나만 있거나 다른 계정도 사용할 수 없는 경우, 복구 후 즉시 &quot;가용성이 돌아온 것&quot;을 볼 수 있어야 합니다.</p><p>검증 방법:</p><ol><li>토큰 새로고침을 트리거하는 요청 보내기(예: 토큰이 만료에 가까워질 때까지 기다린 후 요청)</li><li>로그에서 &quot;disabled 계정 건너뜀&quot; 프롬프트가 더 이상 나타나지 않는지 관찰</li></ol><p><strong>예상 결과</strong>: 요청이 정상적으로 통과하며 로그에 더 이상 해당 계정에 대한 <code>invalid_grant</code> 비활성화 프로세스가 나타나지 않습니다.</p><h2 id="일반적인-문제" tabindex="-1">일반적인 문제 <a class="header-anchor" href="#일반적인-문제" aria-label="Permalink to &quot;일반적인 문제&quot;">​</a></h2><h3 id="❌-disabled를-일시적인-로테이션-으로-오해" tabindex="-1">❌ disabled를 &quot;일시적인 로테이션&quot;으로 오해 <a class="header-anchor" href="#❌-disabled를-일시적인-로테이션-으로-오해" aria-label="Permalink to &quot;❌ disabled를 &quot;일시적인 로테이션&quot;으로 오해&quot;">​</a></h3><p>UI에서 &quot;계정은 있는&quot; 것만 보면 쉽게 &quot;시스템이 일시적으로 사용하지 않는 것&quot;으로 오해합니다. 하지만 <code>disabled=true</code>는 디스크에 기록되며 재시작 후에도 계속 적용됩니다.</p><h3 id="❌-access-token만-보충하고-refresh-token을-업데이트하지-않음" tabindex="-1">❌ access_token만 보충하고 refresh_token을 업데이트하지 않음 <a class="header-anchor" href="#❌-access-token만-보충하고-refresh-token을-업데이트하지-않음" aria-label="Permalink to &quot;❌ access_token만 보충하고 refresh_token을 업데이트하지 않음&quot;">​</a></h3><p><code>invalid_grant</code>의 트리거 포인트는 <code>access_token</code> 새로고침에 사용되는 <code>refresh_token</code>입니다. 일시적으로 사용할 수 있는 <code>access_token</code>을 얻었지만 <code>refresh_token</code>은 여전히 무효라면 나중에 다시 비활성화가 트리거됩니다.</p><h2 id="확인-체크리스트-✅" tabindex="-1">확인 체크리스트 ✅ <a class="header-anchor" href="#확인-체크리스트-✅" aria-label="Permalink to &quot;확인 체크리스트 ✅&quot;">​</a></h2><ul><li>[ ] 로그에서 <code>invalid_grant</code>가 refresh_token 새로고침 실패에서 오는지 확인할 수 있음</li><li>[ ] <code>disabled</code>와 <code>proxy_disabled</code>의 의미 차이를 알고 있음</li><li>[ ] 계정을 다시 추가하여(OAuth 또는 refresh_token) 계정을 복구할 수 있음</li><li>[ ] 복구가 이미 실행 중인 Proxy에 적용되는지 확인할 수 있음</li></ul><h2 id="이-과정-요약" tabindex="-1">이 과정 요약 <a class="header-anchor" href="#이-과정-요약" aria-label="Permalink to &quot;이 과정 요약&quot;">​</a></h2><ul><li><code>invalid_grant</code>가 트리거되면 Proxy는 계정을 <strong>저장된 disabled</strong>로 만들고 토큰 풀에서 제거하여 반복 실패를 방지</li><li>복구의 핵심은 &quot;명시적 토큰 업데이트&quot;(OAuth를 다시 하거나 새 refresh_token으로 다시 한 번 추가)이며, 시스템은 자동으로 <code>disabled_*</code> 필드를 지움</li><li>데이터 디렉토리의 계정 JSON은 가장 권위 있는 상태 소스임(비활성화/원인/시간이 모두 포함됨)</li></ul><h2 id="다음-과정-예고" tabindex="-1">다음 과정 예고 <a class="header-anchor" href="#다음-과정-예고" aria-label="Permalink to &quot;다음 과정 예고&quot;">​</a></h2><blockquote><p>다음 과정에서는 **<a href="./../auth-401/">401/인증 실패: auth_mode, Header 호환 및 클라이언트 구성 체크리스트</a>**를 학습합니다.</p><p>배울 내용:</p><ul><li>401은 보통 &quot;모드/Key/Header&quot; 어느 계층 불일치인지</li><li>다른 클라이언트가 어떤 인증 Header를 가져야 하는지</li><li>가장 짧은 경로로 자가 검사하고 수정하는 방법</li></ul></blockquote><hr><h2 id="부록-소스-코드-참조" tabindex="-1">부록: 소스 코드 참조 <a class="header-anchor" href="#부록-소스-코드-참조" aria-label="Permalink to &quot;부록: 소스 코드 참조&quot;">​</a></h2><details><summary><strong>클릭하여 소스 코드 위치 펼치기</strong></summary><blockquote><p>업데이트 시간: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>기능</th><th>파일 경로</th><th>행 번호</th></tr></thead><tbody><tr><td>설계 문서: invalid_grant의 문제와 변경 동작</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/proxy-invalid-grant.md#L1-L52" target="_blank" rel="noreferrer"><code>docs/proxy-invalid-grant.md</code></a></td><td>1-52</td></tr><tr><td>계정 풀 로드 시 <code>disabled=true</code> 건너뜀</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L70-L158" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>70-158</td></tr><tr><td>토큰 새로고침 실패 시 <code>invalid_grant</code> 식별 및 계정 비활성화</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L840-L890" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>840-890</td></tr><tr><td><code>disabled/disabled_at/disabled_reason</code> 영구 저장 및 메모리에서 제거</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L942-L969" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>942-969</td></tr><tr><td><code>disabled_reason</code> 자르기(계정 파일 팽창 방지)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L1464-L1471" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>1464-1471</td></tr><tr><td>upsert 시 <code>disabled_*</code> 자동 정리(토큰 변경 시 사용자가 자격 증명을 수정한 것으로 간주)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/account.rs#L178-L206" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/account.rs</code></a></td><td>178-206</td></tr><tr><td>계정 다시 추가 후 자동으로 proxy accounts reload(실행 중 즉시 적용)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L21-L59" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>21-59</td></tr></tbody></table></details>`,49)])])}const p=e(i,[["render",d]]);export{g as __pageData,p as default};
